<?php declare(strict_types=1); $title='Blokkolt időszakok – A Bata'; require __DIR__.'/_layout_start.php'; $e=static fn(mixed $v):string=>htmlspecialchars((string)$v,ENT_QUOTES|ENT_SUBSTITUTE,'UTF-8'); ?>
